def load(path): return json.loads((ROOT/path).read_text(encoding='utf-8'))
def dump(path,obj):
 p=ROOT/path;p.parent.mkdir(parents=True,exist_ok=True);p.write_text(json.dumps(obj,ensure_ascii=False,indent=2)+'\n',encoding='utf-8')

def point_data(point, old_map):
 if point in P:return P[point]
 coord=old_map['points'][point];return (coord, point.replace('_',' ').title())

def svg_card(path,title,subtitle,chapter,index,kind):
 p=ROOT/path;p.parent.mkdir(parents=True,exist_ok=True);title=html.escape(title);subtitle=html.escape(subtitle)
 accents={10:'#bf8a42',11:'#667f9f',12:'#8e4f55'};marks={10:'X',11:'XI',12:'XII'};acc=accents[chapter]
 p.write_text(f'''<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 720 900" role="img" aria-label="{title}"><defs><linearGradient id="g" x2="1" y2="1"><stop stop-color="#050505"/><stop offset=".58" stop-color="#211e20"/><stop offset="1" stop-color="#090909"/></linearGradient><radialGradient id="r"><stop stop-color="{acc}" stop-opacity=".7"/><stop offset="1" stop-color="{acc}" stop-opacity="0"/></radialGradient></defs><rect width="720" height="900" fill="url(#g)"/><circle cx="540" cy="220" r="330" fill="url(#r)"/><path d="M80 116 H640 M80 786 H640" stroke="{acc}" stroke-width="2"/><path d="M92 520 C190 420 300 590 402 446 S566 420 638 530" fill="none" stroke="{acc}" stroke-width="9" opacity=".3"/><text x="526" y="390" text-anchor="middle" fill="{acc}" font-size="100" font-family="Georgia">{marks[chapter]}</text><text x="62" y="82" fill="{acc}" font-size="18" font-family="Arial" letter-spacing="4">ROME · CHAPTER {chapter:02d}</text><text x="62" y="650" fill="#fff8e9" font-size="35" font-family="Georgia">{title[:33]}</text><text x="62" y="708" fill="#d8d0c2" font-size="20" font-family="Arial">{subtitle[:61]}</text><text x="62" y="832" fill="{acc}" font-size="18" font-family="Arial" letter-spacing="3">{kind.upper()} · CODEX OF HISTORY · {index:02d}</text></svg>''',encoding='utf-8')

def make_card(item,chapter,source,acquisition,old_map):
 cid,title,original,typ,subtitle,date,point,rarity=item
 coord,label=point_data(point,old_map);local=f'assets/cards/rome/chapter_{chapter:02d}/{cid.lower()}.svg';ch=next(c for c in CHAPTERS if c['number']==chapter)
 era='Ранняя Римская империя' if chapter<12 else 'Поздняя Римская империя'
